// Parse Retell call_analyzed webhook payload
const input = $input.first().json;
const body = input.body || input;

const callId = body.call_id || body.call?.call_id || 'unknown';
const agentId = body.agent_id || body.call?.agent_id || 'unknown';
const fromNumber = body.from_number || body.call?.from_number || 'unknown';
const toNumber = body.to_number || body.call?.to_number || 'unknown';
const callDuration = body.call_duration_ms || body.duration_ms || 0;
const callStatus = body.call_status || body.status || 'completed';
const disconnectReason = body.disconnect_reason || 'unknown';

// Extract transcript
let transcript = '';
if (body.transcript) {
  transcript = body.transcript;
} else if (body.call?.transcript) {
  transcript = body.call.transcript;
} else if (Array.isArray(body.transcript_object)) {
  transcript = body.transcript_object
    .map(t => `${t.role}: ${t.content}`)
    .join('\n');
}

// Pass config variables through
const slackChannel = input.slackChannel || '#sales-alerts';
const leadScoreThreshold = input.leadScoreThreshold || 7;
const googleSheetId = input.googleSheetId || '';
const sheetName = input.sheetName || 'Call Log';

return [{
  json: {
    callId,
    agentId,
    fromNumber,
    toNumber,
    callDurationSeconds: Math.round(callDuration / 1000),
    callStatus,
    disconnectReason,
    transcript,
    slackChannel,
    leadScoreThreshold,
    googleSheetId,
    sheetName,
    analyzedAt: new Date().toISOString()
  }
}];

// Extract and structure the AI analysis response
const input = $input.first().json;
const prev = $('Parse call transcript and metadata').first().json;

let analysis;
try {
  const content = input.message?.content || input.text || input.content || JSON.stringify(input);
  const jsonStr = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analysis = JSON.parse(jsonStr);
} catch (e) {
  analysis = {
    sentiment: 'neutral',
    leadScore: 5,
    summary: 'AI analysis could not be parsed. Manual review recommended.',
    actionItems: ['Review call recording manually'],
    keyTopics: [],
    buyingSignals: [],
    objections: [],
    recommendedNextStep: 'Follow up with prospect'
  };
}

return [{
  json: {
    ...prev,
    sentiment: analysis.sentiment,
    leadScore: analysis.leadScore,
    summary: analysis.summary,
    actionItems: analysis.actionItems || [],
    keyTopics: analysis.keyTopics || [],
    buyingSignals: analysis.buyingSignals || [],
    objections: analysis.objections || [],
    recommendedNextStep: analysis.recommendedNextStep || 'Follow up',
    isQualified: analysis.leadScore >= (prev.leadScoreThreshold || 7)
  }
}];

